#include <cassert>
#include <vector>
#include <string>
#include <iostream>

void check_correctness() {
    // Test case 1: Basic pattern matching
    {
        std::string text = "ABABCABCABABABD";
        std::string pattern = "ABABD";
        std::vector<int> result = kmp_search(text, pattern);
        assert(result == std::vector<int>{10});
    }

    // Test case 2: Multiple occurrences
    {
        std::string text = "AAAA";
        std::string pattern = "AA";
        std::vector<int> result = kmp_search(text, pattern);
        assert((result == std::vector<int>{0, 1, 2}));
    }

    // Test case 3: Pattern not found
    {
        std::string text = "ABCDEF";
        std::string pattern = "XYZ";
        std::vector<int> result = kmp_search(text, pattern);
        assert(result.empty());
    }

    // Test case 4: Empty pattern
    {
        std::string text = "ABCDEF";
        std::string pattern = "";
        std::vector<int> result = kmp_search(text, pattern);
        assert(result.empty());
    }

    // Test case 5: Empty text
    {
        std::string text = "";
        std::string pattern = "ABC";
        std::vector<int> result = kmp_search(text, pattern);
        assert(result.empty());
    }

    // Test case 6: Pattern longer than text
