#include <cassert>
#include <memory>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

void check_correctness() {
    ComponentRegistry registry;

    // Test 1: Basic component creation and retrieval
    auto button = make_shared<Component>(\"Button\", \"Basic button\");
    button->addAttribute(Attribute(\"text\", \"string\", \"\"));
    registry.addComponent(\"Button\", button);
    auto retrieved = registry.getComponent(\"Button\");
    assert(retrieved->getName() == \"Button\");
    assert(retrieved->getDescription() == \"Basic button\");
    assert(retrieved->getAttributes().size() == 1);

    // Test 2: Nested components
    auto primary = make_shared<Component>(\"Primary\", \"Primary button\");
    registry.addComponent(\"Button.Primary\", primary);
    retrieved = registry.getComponent(\"Button.Primary\");
    assert(retrieved->getName() == \"Primary\");

    // Test 3: Non-existent component
    assert(registry.getComponent(\"NonExistent\") == nullptr);

    // Test 4: List all components
    auto components = registry.listAllComponents();
    assert(components.size() == 2);
    assert(find(components.begin(), components.end(), \"Button\") != components.end());
    assert(find(components.begin(), components.end(), \"Button.Primary\") != components.end());

    // Test 5: Multiple attributes
    auto complex = make_shared<Component>(\"Complex\", \"Complex component\");
    complex->addAttribute(Attribute(\"color\", \"string\", \"blue\"));
    complex->addAttribute(Attribute(\"size\", \"number\", \"16\"));
    registry.addComponent(\"Complex\", complex);
    retrieved = registry.getComponent(\"Complex\");
    assert(retrieved->getAttributes().size() == 2);

    cout << \"All tests passed!\" << endl;
}

