    assert(dns.lookupIP(\"192.168.1.2\") == \"Not found\");

    // Test duplicate prevention
    assert(dns.addRecord(\"new.com\", \"192.168.1.3\") == false);
    assert(dns.addRecord(\"example.com\", \"192.168.1.4\") == false);

    // Test non-existent records
    assert(dns.removeRecord(\"nonexistent.com\") == false);
    assert(dns.updateRecord(\"nonexistent.com\", \"192.168.1.5\") == false);

    std::cout << \"All test cases passed!\" << std::endl;
