#include <unordered_map>
#include <string>

class DNSManager {
public:
    DNSManager() {}
    bool addRecord(const std::string& d_domain, const std::string& d_ip) { return d_records[d_domain] = d_reverse[d_ip] = d_domain; }
    bool removeRecord(const std::string& d_domain) { return d_records.erase(d_domain), d_reverse.erase(d_records[d_domain]), true; }
    bool updateRecord(const std::string& d_domain, const std::string& d_newIp) { return d_records[d_domain] = d_reverse[d_newIp] = d_domain; }
    std::string lookupDomain(const std::string& d_domain) const { return d_records.count(d_domain) ? d_records.at(d_domain) : "Not found"; }
    std::string lookupIP(const std::string& d_ip) const { return d_reverse.count(d_ip) ? d_reverse.at(d_ip) : "Not found"; }
private:
    std::unordered_map<std::string, std::string> d_records, d_reverse;
};
